external_knowledge:
- 'typical expected and real power output' refers to the average target and actual generation values; 
- 'each area' corresponds to every region listed in the database;
- 'summary' indicates the need for aggregated data, specifically averages.

sql:
SELECT region_name, industry_type
FROM regions
ORDER BY population DESC;

SELECT industry_type, AVG(population) AS average_population
FROM regions
GROUP BY industry_type;

SELECT AVG(economy_growth_rate) AS average_growth_rate
FROM years
WHERE year_name = 2023;

SELECT AVG(target) AS average_target_generation
FROM forecasts
WHERE region_id = 1;
